<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0">
  <title>Order History — {{ plant_name }}</title>
  <style>
    /* ── Reset ── */
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    /* ── Tokens ── */
    :root {
      --brand:       #075e54;
      --brand-light: #e8f5e9;
      --brand-mid:   #128c7e;
      --ink:         #1a1a1a;
      --ink-mid:     #555;
      --ink-muted:   #999;
      --surface:     #ffffff;
      --bg:          #f0f4f2;
      --border:      #e5ece9;
      --radius-card: 14px;
      --radius-pill: 99px;
    }
    /* ── Base ── */
    html { -webkit-text-size-adjust: 100%; }
    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
      background: var(--bg);
      color: var(--ink);
      min-height: 100vh;
    }
    /* ── Header ── */
    .header {
      background: var(--brand);
      padding: 20px 20px 28px;
      position: relative;
    }
    .header-plant {
      font-size: 11px;
      font-weight: 700;
      letter-spacing: .12em;
      text-transform: uppercase;
      color: rgba(255,255,255,.6);
      margin-bottom: 4px;
    }
    .header-name {
      font-size: 22px;
      font-weight: 700;
      color: #fff;
      line-height: 1.2;
    }
    .header-sub {
      font-size: 13px;
      color: rgba(255,255,255,.65);
      margin-top: 4px;
    }
    /* Wave divider */
    .header-wave {
      position: absolute;
      bottom: -1px; left: 0; right: 0;
      height: 20px;
      background: var(--bg);
      clip-path: ellipse(55% 100% at 50% 100%);
    }
    /* ── Summary strip ── */
    .summary {
      display: flex;
      gap: 10px;
      padding: 20px 16px 8px;
    }
    .stat {
      flex: 1;
      background: var(--surface);
      border-radius: var(--radius-card);
      padding: 14px 12px;
      text-align: center;
      box-shadow: 0 1px 4px rgba(0,0,0,.06);
    }
    .stat-number {
      font-size: 26px;
      font-weight: 800;
      color: var(--brand);
      line-height: 1;
    }
    .stat-label {
      font-size: 11px;
      color: var(--ink-muted);
      margin-top: 4px;
      font-weight: 500;
    }
    /* ── Section ── */
    .section { padding: 8px 16px 24px; }
    .day-label {
      font-size: 11px;
      font-weight: 700;
      letter-spacing: .09em;
      text-transform: uppercase;
      color: var(--brand);
      padding: 16px 4px 8px;
      display: flex;
      align-items: center;
      gap: 8px;
    }
    .day-label::after {
      content: '';
      flex: 1;
      height: 1px;
      background: var(--border);
    }
    /* ── Order card ── */
    .order-card {
      background: var(--surface);
      border-radius: var(--radius-card);
      box-shadow: 0 1px 4px rgba(0,0,0,.07);
      margin-bottom: 10px;
      overflow: hidden;
      border-left: 3px solid var(--brand);
    }
    .order-card-head {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 12px 16px 10px;
      border-bottom: 1px solid var(--border);
    }
    .order-time {
      font-size: 12px;
      color: var(--ink-muted);
    }
    .delivery-badge {
      font-size: 11px;
      background: var(--brand-light);
      color: var(--brand);
      border-radius: var(--radius-pill);
      padding: 3px 9px;
      font-weight: 600;
    }
    .order-items {
      padding: 12px 16px;
      display: flex;
      flex-direction: column;
      gap: 8px;
    }
    .item-row {
      display: flex;
      justify-content: space-between;
      align-items: baseline;
      gap: 8px;
    }
    .item-name {
      font-size: 14px;
      font-weight: 600;
      color: var(--ink);
      flex: 1;
    }
    .item-qty {
      font-size: 13px;
      color: var(--brand-mid);
      font-weight: 700;
      white-space: nowrap;
      background: var(--brand-light);
      border-radius: var(--radius-pill);
      padding: 2px 10px;
      font-variant-numeric: tabular-nums;
    }
    .item-divider {
      height: 1px;
      background: var(--border);
      margin: 2px 0;
    }
    /* unclear items */
    .unclear-section {
      padding: 0 16px 12px;
      border-top: 1px dashed #fcd5d5;
      margin-top: 2px;
      background: #fffafa;
    }
    .unclear-label {
      font-size: 11px;
      color: #e53e3e;
      font-weight: 700;
      padding: 8px 0 6px;
    }
    .unclear-item {
      font-size: 12px;
      font-family: 'SF Mono', 'Fira Code', monospace;
      color: #c53030;
      padding: 2px 0;
    }
    /* ── Empty state ── */
    .empty {
      text-align: center;
      padding: 48px 24px;
      color: var(--ink-muted);
    }
    .empty-icon { font-size: 40px; margin-bottom: 12px; }
    .empty-text { font-size: 15px; font-weight: 600; color: var(--ink-mid); margin-bottom: 6px; }
    .empty-sub  { font-size: 13px; line-height: 1.6; }
    /* ── Footer ── */
    .footer {
      text-align: center;
      padding: 16px 24px 32px;
      font-size: 11px;
      color: var(--ink-muted);
      line-height: 1.7;
    }
  </style>
</head>
<body>
<div class="header">
  <div class="header-plant">{{ plant_name }}</div>
  <div class="header-name">{{ customer_name }}</div>
  <div class="header-sub">Order history · last {{ ledger_days }} days</div>
  <div class="header-wave"></div>
</div>
<div class="summary">
  <div class="stat">
    <div class="stat-number">{{ total_orders }}</div>
    <div class="stat-label">Orders</div>
  </div>
  <div class="stat">
    <div class="stat-number">{{ days|length }}</div>
    <div class="stat-label">Days active</div>
  </div>
  <div class="stat">
    <div class="stat-number">{{ ledger_days }}</div>
    <div class="stat-label">Day window</div>
  </div>
</div>
<div class="section">
  {% if days %}
    {% for day in days %}
      <div class="day-label">{{ day.label }}</div>
      {% for order in day.orders %}
        <div class="order-card">
          <div class="order-card-head">
            <span class="order-time">Placed at {{ order.created_at }}</span>
            {% if order.delivery_time %}
              <span class="delivery-badge">🕒 {{ order.delivery_time }}</span>
            {% endif %}
          </div>
          {% if order.order_lines %}
            <div class="order-items">
              {% for item in order.order_lines %}
                <div class="item-row">
                  <span class="item-name">{{ item.product }}</span>
                  <span class="item-qty">
                    {% set qty = item.quantity %}
                    {% if qty == qty | int %}{{ qty | int }}{% else %}{{ qty }}{% endif %}
                    {{ item.unit }}
                  </span>
                </div>
                {% if not loop.last %}<div class="item-divider"></div>{% endif %}
              {% endfor %}
            </div>
          {% endif %}
          {% if order.unclear_items %}
            <div class="unclear-section">
              <div class="unclear-label">⚠️ Couldn't recognise</div>
              {% for raw in order.unclear_items %}
                <div class="unclear-item">• {{ raw }}</div>
              {% endfor %}
            </div>
          {% endif %}
        </div>
      {% endfor %}
    {% endfor %}
  {% else %}
    <div class="empty">
      <div class="empty-icon">📋</div>
      <div class="empty-text">No orders in the last {{ ledger_days }} days</div>
      <div class="empty-sub">Your orders will appear here<br>as soon as you place one.</div>
    </div>
  {% endif %}
</div>
<div class="footer">
  Generated {{ generated_at }} IST<br>
  Showing confirmed orders only · Cancelled orders not shown
</div>
</body>
</html>class Customer(Base)
