<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0">
    <title>OrdeRR — {{ plant_name }} Dashboard</title>
    <style>
        * { margin:0; padding:0; box-sizing:border-box; }
        body { font-family:'Segoe UI',sans-serif; background:#f0f2f5; color:#333; }
        /* ── Header ── */
        .header { background:#075e54; color:white; padding:14px 16px; display:flex; justify-content:space-between; align-items:center; }
        .header h1 { font-size:18px; }
        .header-right { font-size:12px; opacity:.85; }
        /* ── Tab Nav — horizontal scroll on mobile ── */
        .tab-nav { background:white; border-bottom:2px solid #e0e0e0; display:flex; overflow-x:auto; -webkit-overflow-scrolling:touch; scrollbar-width:none; padding:0 8px; }
        .tab-nav::-webkit-scrollbar { display:none; }
        .tab-btn { padding:13px 14px; border:none; background:none; cursor:pointer; font-size:13px; color:#888; border-bottom:3px solid transparent; margin-bottom:-2px; transition:all .2s; white-space:nowrap; flex-shrink:0; }
        .tab-btn.active { color:#075e54; border-bottom-color:#075e54; font-weight:600; }
        .tab-btn.hidden { display:none; }
        .tab-pane { display:none; }
        .tab-pane.active { display:block; }
        /* ── Cards — 2-col on mobile, 4-col on desktop ── */
        .cards { display:grid; grid-template-columns:repeat(2,1fr); gap:10px; padding:12px; }
        @media(min-width:600px){ .cards { grid-template-columns:repeat(4,1fr); gap:16px; padding:20px 24px; } }
        .card { background:white; border-radius:12px; padding:16px; box-shadow:0 1px 4px rgba(0,0,0,.1); text-align:center; }
        .card .number { font-size:30px; font-weight:bold; color:#075e54; }
        .card .label { font-size:12px; color:#888; margin-top:4px; }
        .card.warning .number { color:#e67e22; }
        .card.success .number { color:#27ae60; }
        .card.danger  .number { color:#c62828; }
        /* ── Section ── */
        .section { padding:0 12px 20px; }
        @media(min-width:600px){ .section { padding:0 24px 24px; } }
        .section h2 { font-size:15px; color:#555; margin-bottom:12px; padding-bottom:8px; border-bottom:2px solid #075e54; display:flex; justify-content:space-between; align-items:center; flex-wrap:wrap; gap:8px; }
        /* ── Tables ── */
        .summary-table { background:white; border-radius:12px; overflow:hidden; box-shadow:0 1px 4px rgba(0,0,0,.1); margin-bottom:20px; }
        .summary-table table { width:100%; border-collapse:collapse; }
        .summary-table th { background:#075e54; color:white; padding:10px 12px; text-align:left; font-size:12px; }
        .summary-table td { padding:10px 12px; border-bottom:1px solid #f0f0f0; font-size:13px; vertical-align:middle; }
        .summary-table tr:last-child td { border-bottom:none; }
        .product-table-wrap { overflow-x:auto; -webkit-overflow-scrolling:touch; }
        /* ── Mobile Cards ── */
        .mobile-card { background:white; border-radius:12px; padding:14px 16px; margin-bottom:10px; box-shadow:0 1px 4px rgba(0,0,0,.1); border-left:4px solid #075e54; }
        .mobile-card.inactive { opacity:.6; border-left-color:#ccc; }
        .mobile-card-row { display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:6px; }
        .mobile-card-name { font-weight:700; font-size:15px; color:#222; }
        .mobile-card-sub { font-size:12px; color:#888; margin-top:2px; }
        .mobile-card-actions { display:flex; gap:6px; flex-wrap:wrap; margin-top:10px; }
        /* Desktop/mobile visibility */
        .desktop-only { display:none; }
        @media(min-width:700px){ .desktop-only { display:block; } .mobile-only { display:none !important; } }
        .mobile-only { display:block; }
        @media(min-width:700px){ .mobile-only { display:none !important; } }
        /* ── Order Cards ── */
        .order-card { background:white; border-radius:12px; padding:14px 16px; margin-bottom:10px; box-shadow:0 1px 4px rgba(0,0,0,.1); border-left:4px solid #075e54; }
        .order-card.unclear { border-left-color:#e67e22; }
        .order-header { display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:8px; gap:8px; flex-wrap:wrap; }
        .items { font-size:13px; color:#555; line-height:1.8; }
        .raw-message { font-size:12px; color:#e67e22; margin-top:8px; font-style:italic; word-break:break-word; }
        .reason { font-size:12px; color:#e67e22; margin-top:4px; }
        /* ── Badges ── */
        .badge { padding:3px 8px; border-radius:20px; font-size:11px; font-weight:bold; display:inline-block; white-space:nowrap; }
        .badge.unclear    { background:#fff3e0; color:#e65100; }
        .badge.inactive   { background:#fce4ec; color:#c62828; }
        .badge.active     { background:#e8f5e9; color:#2e7d32; }
        .badge.unassigned { background:#fff8e1; color:#f57f17; }
        .badge.pending-badge  { background:#fce4ec; color:#c62828; }
        .badge.ordered-badge  { background:#e8f5e9; color:#2e7d32; }
        .badge.failed-badge   { background:#fce4ec; color:#c62828; }
        .badge.manual-badge   { background:#fff3e0; color:#e65100; }
        .badge.attempts-badge { background:#f5f5f5; color:#757575; }
        .badge.ack-badge      { background:#fff3e0; color:#e65100; }
        .badge-count { display:inline-block; background:#e53e3e; color:white; border-radius:9999px; padding:1px 6px; font-size:11px; margin-left:4px; font-weight:700; }
        /* ── Buttons ── */
        .btn { border:none; border-radius:6px; padding:7px 13px; font-size:12px; cursor:pointer; font-weight:600; transition:background .15s; white-space:nowrap; }
        .btn-deactivate { background:#fce4ec; color:#c62828; }
        .btn-activate   { background:#e8f5e9; color:#2e7d32; }
        .btn-assign     { background:#e3f2fd; color:#1565c0; }
        .btn-save       { background:#075e54; color:white; }
        .btn-cancel-ui  { background:#f5f5f5; color:#555; }
        .btn-retry      { background:#e8f5e9; color:#2e7d32; }
        .btn-resolve    { background:#f5f5f5; color:#555; }
        .section-btn { font-size:12px; background:#075e54; color:white; border:none; border-radius:6px; padding:5px 12px; cursor:pointer; font-weight:600; }
        /* ── Date nav ── */
        .date-nav { display:flex; align-items:center; gap:8px; margin-bottom:14px; background:white; padding:10px 12px; border-radius:10px; box-shadow:0 1px 4px rgba(0,0,0,.08); flex-wrap:wrap; }
        .date-nav-label { font-weight:600; font-size:14px; color:#075e54; flex:1; text-align:center; }
        /* ── Add SP Panel ── */
        .add-sp-panel { background:white; border-radius:12px; padding:16px; margin-bottom:16px; box-shadow:0 1px 4px rgba(0,0,0,.1); display:none; }
        .add-sp-panel.open { display:block; }
        .add-sp-panel h3 { font-size:14px; color:#075e54; margin-bottom:12px; }
        .add-sp-form { display:flex; flex-direction:column; gap:10px; }
        .add-sp-form label { font-size:12px; color:#666; display:block; margin-bottom:3px; }
        .add-sp-form input { padding:10px 12px; border:1px solid #ccc; border-radius:8px; font-size:15px; width:100%; }
        .add-sp-btns { display:flex; gap:8px; }
        /* ── Pending ── */
        .pending-group { background:white; border-radius:12px; padding:14px 16px; margin-bottom:14px; box-shadow:0 1px 4px rgba(0,0,0,.1); }
        .pending-group h3 { font-size:14px; color:#075e54; margin-bottom:10px; display:flex; justify-content:space-between; align-items:center; }
        .pending-list { list-style:none; }
        .pending-list li { padding:7px 0; border-bottom:1px solid #f5f5f5; font-size:13px; display:flex; justify-content:space-between; align-items:center; }
        .pending-list li:last-child { border-bottom:none; }
        /* ── Window Status ── */
        .window-filter-bar { display:flex; gap:6px; margin-bottom:14px; flex-wrap:wrap; overflow-x:auto; -webkit-overflow-scrolling:touch; }
        .filter-btn { padding:6px 12px; border-radius:20px; border:1px solid #ddd; background:white; font-size:12px; cursor:pointer; font-weight:600; color:#888; white-space:nowrap; }
        .filter-btn.active { border-color:#075e54; background:#075e54; color:white; }
        .window-mobile-card { background:white; border-radius:12px; padding:14px 16px; margin-bottom:10px; box-shadow:0 1px 4px rgba(0,0,0,.1); display:flex; align-items:center; gap:12px; }
        .window-dot { width:12px; height:12px; border-radius:50%; flex-shrink:0; }
        .dot-open   { background:#27ae60; }
        .dot-atrisk { background:#e67e22; }
        .dot-closed { background:#c62828; }
        .window-info { flex:1; min-width:0; }
        .window-info-name { font-weight:700; font-size:14px; white-space:nowrap; overflow:hidden; text-overflow:ellipsis; }
        .window-info-sub { font-size:11px; color:#aaa; margin-top:2px; }
        .window-status-text { font-size:13px; font-weight:700; white-space:nowrap; }
        .ws-open   { color:#27ae60; }
        .ws-atrisk { color:#e67e22; }
        .ws-closed { color:#c62828; }
        .window-checked { font-size:11px; color:#aaa; padding:8px 0 4px; text-align:center; }
        /* ── Failed Cards ── */
        .failed-card { background:white; border-radius:12px; padding:14px 16px; margin-bottom:10px; box-shadow:0 1px 4px rgba(0,0,0,.1); border-left:4px solid #c62828; }
        .failed-card.manual { border-left-color:#e65100; }
        .failed-card-header { display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:8px; gap:8px; }
        .failed-card-phone { font-weight:700; font-size:14px; color:#333; }
        .failed-card-time { font-size:11px; color:#aaa; white-space:nowrap; }
        .failed-card-message { font-size:13px; color:#555; background:#fafafa; border-radius:6px; padding:10px 12px; margin:8px 0; border-left:3px solid #e0e0e0; font-style:italic; word-break:break-word; }
        .failed-card-reason { font-size:12px; color:#c62828; margin:4px 0 10px; }
        .failed-card-reason.orange { color:#e65100; }
        .failed-card-meta { display:flex; gap:6px; align-items:center; flex-wrap:wrap; }
        .failed-card-actions { display:flex; gap:8px; margin-top:12px; }
        /* ── Unclear Tab ── */
        .unclear-order-card { background:white; border-radius:12px; padding:14px 16px; margin-bottom:12px; box-shadow:0 1px 4px rgba(0,0,0,.1); border-left:4px solid #e53e3e; }
        .unclear-order-header { display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:10px; gap:8px; flex-wrap:wrap; }
        .unclear-order-name { font-weight:700; font-size:15px; color:#222; }
        .unclear-order-meta { font-size:12px; color:#888; margin-top:2px; }
