        .unclear-raw-pill { font-size:13px; font-family:monospace; background:#fff5f5; border:1px solid #fed7d7; border-radius:6px; padding:4px 10px; color:#c53030; flex:1; min-width:120px; word-break:break-all; }
        .unclear-select { font-size:13px; padding:5px 8px; border:1px solid #e2e8f0; border-radius:6px; flex:1; min-width:150px; max-width:240px; background:white; }
        .unclear-save-btn { font-size:12px; background:#3182ce; color:white; border:none; border-radius:6px; padding:5px 12px; cursor:pointer; white-space:nowrap; font-weight:600; }
