        .modal-box { background:white; border-radius:16px 16px 0 0; padding:0; width:100%; max-width:100%; max-height:90vh; overflow:hidden; display:flex; flex-direction:column; box-shadow:0 -4px 24px rgba(0,0,0,.2); }
        @media(min-width:600px){ .modal-box { border-radius:14px; width:520px; max-width:95vw; max-height:85vh; } }
        .modal-header { padding:16px 20px 14px; border-bottom:1px solid #f0f0f0; display:flex; justify-content:space-between; align-items:center; }
