<div class="header">
    <div><h1>OrdeRR — {{ plant_name }}</h1></div>
    <div class="header-right">{{ current_time }} IST</div>
</div>
<div class="tab-nav">
    <button class="tab-btn active" onclick="switchTab('orders',this)">📦 Orders</button>
    <button class="tab-btn" onclick="switchTab('pending',this)">⏳ Pending</button>
    <button class="tab-btn" onclick="switchTab('unclear',this)" id="unclear-tab-btn">⚠️ Unclear</button>
    <button class="tab-btn" onclick="switchTab('customers',this)">👥 Customers</button>
    <button class="tab-btn" onclick="switchTab('salespersons',this)">🧑 Sales</button>
    <button class="tab-btn" onclick="switchTab('window',this)" id="window-tab-btn">📡 Windows</button>
    <button class="tab-btn {% if not reliability_stats.has_issues %}hidden{% endif %}" onclick="switchTab('failed',this)" id="failed-tab-btn">⚠️ Failed<span class="tab-dot"></span></button>
</div>
<div id="tab-orders" class="tab-pane active">
    <div class="cards">
        <div class="card"><div class="number">{{ orders|length }}</div><div class="label">Total Orders</div></div>
        <div class="card success"><div class="number">{{ clear_orders|length }}</div><div class="label">Clear</div></div>
        <div class="card warning"><div class="number">{{ unclear_orders|length }}</div><div class="label">Attention</div></div>
        <div class="card"><div class="number">{{ total_items }}</div><div class="label">Items</div></div>
    </div>
    <div class="section">
        <div class="date-nav">
            <a href="/dashboard/?view_date={{ yesterday }}"><button class="btn btn-assign">◀</button></a>
            <span class="date-nav-label">{{ target_date_display }}{% if is_today %} <span style="font-size:11px;color:#888">(Today)</span>{% endif %}</span>
            {% if not is_today %}
            <a href="/dashboard/?view_date={{ tomorrow }}"><button class="btn btn-assign">▶</button></a>
            {% else %}
            <button class="btn" disabled style="opacity:.3">▶</button>
            {% endif %}
            <a href="/dashboard/"><button class="btn btn-save" {% if is_today %}style="opacity:.4"{% endif %}>Today</button></a>
            <button class="btn btn-assign" onclick="location.reload()">↻</button>
        </div>
        <h2>📊 Product Summary</h2>
        <div class="summary-table product-table-wrap">
            <table>
                <thead><tr><th>Product</th><th>Qty</th><th>Unit</th><th>#</th></tr></thead>
                <tbody>
                    {% if product_summary %}
                        {% for item in product_summary %}
                        <tr><td>{{ item.product }}</td><td><strong>{{ item.total_quantity }}</strong></td><td>{{ item.unit }}</td><td>{{ item.orders_count }}</td></tr>
                        {% endfor %}
                    {% else %}
                        <tr><td colspan="4" style="text-align:center;color:#aaa">No orders for this date</td></tr>
                    {% endif %}
                </tbody>
            </table>
        </div>
        <h2>✅ Orders</h2>
        {% if clear_orders %}
            {% for order in clear_orders %}
            <div class="order-card">
                <div class="order-header">
                    <div>
                        <span style="font-weight:bold;font-size:15px">{{ order.customer_name or order.customer_phone }}</span>
                        {% if order.has_unclear_items %}
                        <span class="badge unclear" style="margin-left:6px;font-size:10px">⚠️ partial</span>
                        {% endif %}
                    </div>
                    <span style="font-size:11px;color:#888">
                        {% if order.delivery_date and order.delivery_time %}{{ order.delivery_date }} · {{ order.delivery_time }}
                        {% elif order.delivery_date %}{{ order.delivery_date }}
                        {% else %}No date{% endif %}
                        {% if order.created_at %}
                        · <span style="color:#aaa">{{ order.created_at.strftime('%I:%M %p') }}</span>
                        {% endif %}
                    </span>
                </div>
                <div class="items">{% for item in order.items_parsed %}{{ item.product }} — {{ item.quantity }} {{ item.unit }}<br>{% endfor %}
                                {% if is_before_cutoff %}
                {% if not order.is_next_day_override %}
                    <div style="margin-top:8px;display:flex;gap:8px;flex-wrap:wrap;">
                    <button class="btn btn-assign" onclick="moveToNextDay({{ order.id }})">➡ Next Day</button>
                    <button class="btn btn-deactivate" onclick="cancelOrder({{ order.id }}, '{{ order.customer_name or order.customer_phone }}')">🚫 Cancel Order</button>
                    </div>
                {% else %}
                    <div style="margin-top:8px;display:flex;gap:8px;align-items:center;flex-wrap:wrap;">
                    <span class="badge" style="background:#e8f5e9;color:#2e7d32">✅ Next Day</span>
                    <button class="btn btn-cancel-ui" onclick="revertToToday({{ order.id }})">↩ Revert</button>
                    <button class="btn btn-deactivate" onclick="cancelOrder({{ order.id }}, '{{ order.customer_name or order.customer_phone }}')">🚫 Cancel Order</button>
                    </div>
                {% endif %}
                {% else %}
                {% if order.is_next_day_override %}
                    <div style="margin-top:8px;display:flex;gap:8px;align-items:center;flex-wrap:wrap;">
                    <span class="badge" style="background:#e8f5e9;color:#2e7d32">✅ Next Day (locked)</span>
                    <button class="btn btn-deactivate" onclick="cancelOrder({{ order.id }}, '{{ order.customer_name or order.customer_phone }}')">🚫 Cancel Order</button>
                    </div>
                {% else %}
                    <div style="margin-top:8px;">
                    <button class="btn btn-deactivate" onclick="cancelOrder({{ order.id }}, '{{ order.customer_name or order.customer_phone }}')">🚫 Cancel Order</button>
                    </div>
                {% endif %}
                {% endif %}
                </div>
                {% if order.has_unclear_items %}
                <div style="margin-top:10px; padding-top:10px; border-top:1px dashed #fed7d7;">
                    <div style="font-size:12px; font-weight:700; color:#e53e3e; margin-bottom:4px;">❓ Unresolved items (not counted in summary):</div>
                    {% for raw in order.unclear_items_list %}
                    <div style="font-size:12px; font-family:monospace; color:#c53030; padding:2px 0;">• {{ raw }}</div>
                    {% endfor %}
                </div>
                {% endif %}
                {% if order.raw_message and order.has_unclear_items %}
                <details style="margin-top:8px;">
                    <summary style="font-size:12px;color:#aaa;cursor:pointer;">📄 Raw message</summary>
                    <div class="raw-message">{{ order.raw_message }}</div>
                </details>
                {% endif %}
            </div>
            {% endfor %}
        {% else %}
            <div class="empty">No clear orders for this date</div>
        {% endif %}
        {% if unclear_orders %}
        <h2 style="margin-top:8px">⚠️ Unclear Orders</h2>
        {% for order in unclear_orders %}
        <div class="order-card unclear">
            <div class="order-header">
                <span style="font-weight:bold">{{ order.customer_name or order.customer_phone }}</span>
                <span class="badge unclear">unclear</span>
            </div>
            <div class="raw-message">"{{ order.raw_message }}"</div>
            <div class="reason">{{ order.unclear_reason or 'Unknown reason' }}</div>
        </div>
        {% endfor %}
        {% endif %}
    </div>
</div>
<div id="tab-pending" class="tab-pane">
    <div class="cards">
        <div class="card warning"><div class="number" id="pending-total">—</div><div class="label">Pending</div></div>
        <div class="card"><div class="number" id="pending-groups">—</div><div class="label">Salespersons</div></div>
        <div class="card warning"><div class="number" id="pending-unassigned">—</div><div class="label">Unassigned</div></div>
    </div>
    <div class="section">
        <h2>⏳ Pending — Today <button class="section-btn" onclick="loadPending()">↻</button></h2>
        <div id="pending-content"><div class="empty">Loading...</div></div>
    </div>
</div>
<div id="tab-unclear" class="tab-pane">
    <div class="cards">
        <div class="card danger"><div class="number" id="unclear-count">—</div><div class="label">Unclear Orders</div></div>
        <div class="card warning"><div class="number" id="unclear-items-count">—</div><div class="label">Unresolved Items</div></div>
        <div class="card success"><div class="number" id="unclear-aliases-count">—</div><div class="label">Saved Aliases</div></div>
        <div class="card" style="border-top:3px solid #718096;">
            <div class="number" id="unclear-noise-count">—</div>
            <div class="label">Noise Phrases</div>
        </div>
    </div>
    <div class="section">
        <h2>⚠️ Unclear Items <button class="section-btn" onclick="loadUnclearOrders()">↻</button></h2>
        <p style="font-size:13px;color:#718096;margin-bottom:16px;line-height:1.6;">
            These orders had items the parser couldn't recognise. The customer received a normal "✅ Order received" confirmation.
            Assign the correct product below — the system will learn it and retroactively update all past orders with the same text.
        </p>
        <div id="unclear-orders-container">
            <div class="empty">Loading...</div>
        </div>
        <div style="margin-top:24px;">
            <h2>📖 Saved Aliases</h2>
            <p style="font-size:13px;color:#718096;margin-bottom:12px;">These mappings are applied automatically by the parser from now on.</p>
            <div id="aliases-container">
                <div class="empty">Loading...</div>
            </div>
        </div>
        <div style="margin-top:24px;">
            <h2>🚫 Noise Phrases</h2>
            <p style="font-size:13px;color:#718096;margin-bottom:12px;">
                These texts are silently ignored by the parser — never shown as unclear again.
            </p>
            <div id="noise-container">
                <div class="empty">Loading...</div>
            </div>
        </div>
    </div>
</div>
<div id="tab-customers" class="tab-pane">
    <div class="cards">
        <div class="card"><div class="number" id="stat-total">—</div><div class="label">Total</div></div>
        <div class="card success"><div class="number" id="stat-active">—</div><div class="label">Active</div></div>
        <div class="card warning"><div class="number" id="stat-inactive">—</div><div class="label">Inactive</div></div>
        <div class="card success"><div class="number" id="stat-ordered">—</div><div class="label">Ordered</div></div>
    </div>
    <div class="section">
        <h2>👥 Customers
          <div style="display:flex;gap:8px">
            <button class="section-btn" onclick="openAddCustomerModal()">＋ Add Customer</button>
            <button class="section-btn" onclick="loadCustomers()">↻</button>
          </div>
        </h2>
        <div class="desktop-only">
            <div class="summary-table">
                <table>
                    <thead><tr><th>Restaurant</th><th>Phone</th><th>Area</th><th>Salesperson</th><th>Today</th><th>Status</th><th>Actions</th></tr></thead>
                    <tbody id="customer-tbody"><tr><td colspan="7" style="text-align:center;color:#aaa;padding:24px">Loading...</td></tr></tbody>
                </table>
            </div>
        </div>
        <div class="mobile-only" id="customer-cards"><div class="empty">Loading...</div></div>
    </div>
</div>
<div id="tab-salespersons" class="tab-pane">
