        <h2>🧑 Salespersons <button class="section-btn" onclick="toggleAddSP()">+ Add</button></h2>
        <div class="add-sp-panel" id="add-sp-panel">
            <h3>Add New Salesperson</h3>
            <div class="add-sp-form">
                <div><label>Name</label><input type="text" id="sp-name" placeholder="e.g. Rahul" autocomplete="off"/></div>
                <div><label>WhatsApp Number</label><input type="tel" id="sp-phone" placeholder="919XXXXXXXXX" autocomplete="off"/></div>
                <div class="add-sp-btns">
                    <button class="btn btn-save" onclick="addSalesperson()">Save</button>
                    <button class="btn btn-cancel-ui" onclick="toggleAddSP()">Cancel</button>
                </div>
            </div>
        </div>
        <div class="desktop-only">
            <div class="summary-table">
                <table>
                    <thead><tr><th>Name</th><th>Phone</th><th>Customers</th><th>Status</th><th>Actions</th></tr></thead>
                    <tbody id="sp-tbody"><tr><td colspan="5" style="text-align:center;color:#aaa;padding:24px">Loading...</td></tr></tbody>
                </table>
            </div>
        </div>
        <div class="mobile-only" id="sp-cards"><div class="empty">Loading...</div></div>
    </div>
</div>
<div id="tab-window" class="tab-pane">
    <div class="cards">
        <div class="card success"><div class="number" id="win-open">—</div><div class="label">Open</div></div>
        <div class="card warning"><div class="number" id="win-atrisk">—</div><div class="label">At Risk</div></div>
        <div class="card danger"><div class="number" id="win-closed">—</div><div class="label">Closed</div></div>
        <div class="card"><div class="number" id="win-total">—</div><div class="label">Total</div></div>
    </div>
    <div class="section">
        <h2>📡 WA Window Status <button class="section-btn" onclick="loadWindowStatus()">↻</button></h2>
        <div class="window-filter-bar">
            <button class="filter-btn active" onclick="filterWindow('all',this)">All</button>
            <button class="filter-btn" onclick="filterWindow('manager',this)">Manager</button>
            <button class="filter-btn" onclick="filterWindow('salesperson',this)">Salesperson</button>
            <button class="filter-btn" onclick="filterWindow('customer',this)">Customers</button>
            <button class="filter-btn" onclick="filterWindow('CLOSED',this)" style="border-color:#c62828;color:#c62828">🔴 Closed</button>
            <button class="filter-btn" onclick="filterWindow('AT_RISK',this)" style="border-color:#e67e22;color:#e67e22">🟡 At Risk</button>
        </div>
        <div id="window-list"><div class="empty">Loading...</div></div>
        <div class="window-checked" id="window-checked"></div>
        <div class="info-box" style="margin-top:12px">
            <strong>💡 How to read this:</strong><br>
            🟢 <strong>Open</strong> — &gt;4hrs left. Messages deliver fine.<br>
            🟡 <strong>At Risk</strong> — &lt;4hrs left. Call them before 10 PM — ask to send a WhatsApp message to the Fluffy number.<br>
            🔴 <strong>Closed</strong> — Window expired. Call them and ask to send "Hi" to +91 77699 77565.
        </div>
    </div>
</div>
<div id="tab-failed" class="tab-pane">
    <div class="cards">
        <div class="card"><div class="number">{{ reliability_stats.total_today or 0 }}</div><div class="label">Today</div></div>
        <div class="card success"><div class="number">{{ reliability_stats.confirmed_today or 0 }}</div><div class="label">OK</div></div>
        <div class="card {% if reliability_stats.failed_today %}danger{% else %}success{% endif %}"><div class="number">{{ reliability_stats.failed_today or 0 }}</div><div class="label">Failed</div></div>
        <div class="card {% if reliability_stats.manual_review_total %}danger{% else %}success{% endif %}"><div class="number">{{ reliability_stats.manual_review_total or 0 }}</div><div class="label">Manual</div></div>
    </div>
    <div class="section">
        <h2>⚠️ Failed &amp; Review <button class="section-btn" onclick="loadFailedMessages()">↻</button></h2>
        <div id="failed-list">
            {% if failed_messages %}
                {% for m in failed_messages %}
                <div class="failed-card {% if m.processing_status == 'MANUAL_REVIEW' %}manual{% endif %}" id="fc-{{ m.id }}">
                    <div class="failed-card-header">
                        <span class="failed-card-phone">📱 {{ m.customer_phone }}</span>
                        <span class="failed-card-time">{{ m.received_at }}</span>
                    </div>
                    <div class="failed-card-message">{% if m.raw_message %}"{{ m.raw_message }}"{% else %}<em style="color:#aaa">No text</em>{% endif %}</div>
                    <div class="failed-card-reason {% if m.processing_status == 'MANUAL_REVIEW' %}orange{% endif %}">❗ {{ m.failure_reason }}</div>
                    <div class="failed-card-meta">
                        <span class="badge {% if m.processing_status == 'MANUAL_REVIEW' %}manual-badge{% else %}failed-badge{% endif %}">{{ m.processing_status }}</span>
                        <span class="badge attempts-badge">{{ m.attempts }} attempt{{ 's' if m.attempts != 1 else '' }}</span>
                        {% if m.ack_failed %}<span class="badge ack-badge">Ack failed</span>{% endif %}
                        {% if m.linked_order_id %}<span class="badge active">Order #{{ m.linked_order_id }}</span>{% endif %}
                    </div>
                    <div class="failed-card-actions">
                        <button class="btn btn-retry" onclick="retryMessage({{ m.id }})">↻ Retry</button>
                        <button class="btn btn-resolve" onclick="resolveMessage({{ m.id }})">✓ Resolve</button>
                    </div>
                </div>
                {% endfor %}
            {% else %}
                <div class="empty" style="padding:60px">✅ No failed messages.</div>
            {% endif %}
        </div>
    </div>
</div>
<!-- ══════════════════════════════════════════════════════════════════════════
     MODALS
     ══════════════════════════════════════════════════════════════════════════ -->
