<div id="toast"></div>
<script>
let allSalespersons = [];
let currentAssignId = null;
let windowData = [];
let productNames = [];
// ── Core ────────────────────────────────────────────────────────────────────
function switchTab(name, btn) {
    document.querySelectorAll('.tab-pane').forEach(p => p.classList.remove('active'));
    document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
    document.getElementById('tab-' + name).classList.add('active');
    if (btn) btn.classList.add('active');
    if (name === 'customers')    { loadSalespersons().then(loadCustomers); }
    if (name === 'salespersons') { loadSalespersons(); }
    if (name === 'pending')      { loadPending(); }
    if (name === 'failed')       { loadFailedMessages(); }
    if (name === 'window')       { loadWindowStatus(); }
    // ② Updated: also call loadNoisePhrases when switching to unclear
    if (name === 'unclear')      { loadUnclearOrders(); loadAliases(); loadNoisePhrases(); }
}
function showToast(msg, type='') {
    const t = document.getElementById('toast');
    t.textContent = msg; t.className = 'show' + (type ? ' '+type : '');
    setTimeout(() => t.className = '', 3200);
}
async function api(method, path, body) {
    const opts = { method, credentials:'include', headers:{} };
    if (body) { opts.headers['Content-Type']='application/json'; opts.body=JSON.stringify(body); }
    const r = await fetch(path, opts);
    if (r.status === 401) { window.location.reload(); return; } // re-prompt browser auth
    if (!r.ok) throw new Error(await r.text());
    return r.json();
}
function isMobile() { return window.innerWidth < 700; }
function esc(str) {
    return String(str||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}
function closeModal(id) {
    document.getElementById(id).classList.remove('open');
    if (id === 'assign-modal') currentAssignId = null;
}
document.querySelectorAll('.modal-overlay').forEach(el => {
    el.addEventListener('click', e => { if(e.target===el) el.classList.remove('open'); });
});
// ── Salespersons ─────────────────────────────────────────────────────────────
async function loadSalespersons() {
    try {
        const data = await api('GET', '/admin/salespersons');
        allSalespersons = data.salespersons || [];
        renderSalespersons(allSalespersons);
        const sel = document.getElementById('modal-sp');
        if (sel) {
            sel.innerHTML = '<option value="">— Select —</option>';
            allSalespersons.filter(s=>s.active).forEach(s => {
                sel.innerHTML += `<option value="${s.id}">${esc(s.name)}</option>`;
            });
        }
    } catch(e) { console.error(e); }
}
function renderSalespersons(list) {
    const tbody = document.getElementById('sp-tbody');
    if (tbody) {
        if (!list.length) { tbody.innerHTML='<tr><td colspan="5" style="text-align:center;color:#aaa;padding:24px">No salespersons yet</td></tr>'; }
        else tbody.innerHTML = list.map(s=>`<tr>
            <td><strong>${esc(s.name)}</strong></td>
            <td style="color:#888;font-size:13px">${esc(s.phone)}</td>
            <td>${s.customer_count}</td>
            <td>${s.active?'<span class="badge active">Active</span>':'<span class="badge inactive">Inactive</span>'}</td>
            <td>${s.active?`<button class="btn btn-deactivate" onclick="toggleSP(${s.id},false)">Deactivate</button>`:`<button class="btn btn-activate" onclick="toggleSP(${s.id},true)">Activate</button>`}</td>
        </tr>`).join('');
    }
    const cards = document.getElementById('sp-cards');
    if (cards) {
        if (!list.length) { cards.innerHTML='<div class="empty">No salespersons yet</div>'; return; }
        cards.innerHTML = list.map(s=>`
            <div class="mobile-card ${!s.active?'inactive':''}">
                <div class="mobile-card-row">
                    <div><div class="mobile-card-name">${esc(s.name)}</div><div class="mobile-card-sub">${esc(s.phone)} · ${s.customer_count} customers</div></div>
                    ${s.active?'<span class="badge active">Active</span>':'<span class="badge inactive">Inactive</span>'}
                </div>
                <div class="mobile-card-actions">
                    ${s.active?`<button class="btn btn-deactivate" onclick="toggleSP(${s.id},false)">Deactivate</button>`:`<button class="btn btn-activate" onclick="toggleSP(${s.id},true)">Activate</button>`}
                </div>
            </div>`).join('');
    }
}
function toggleAddSP() { document.getElementById('add-sp-panel').classList.toggle('open'); }
async function addSalesperson() {
    const name=document.getElementById('sp-name').value.trim(), phone=document.getElementById('sp-phone').value.trim();
    if(!name||!phone){showToast('Name and phone required','error');return;}
    try {
        await api('POST','/admin/salespersons',{name,phone});
        showToast(`✅ ${name} added`,'success');
        document.getElementById('sp-name').value='';
        document.getElementById('sp-phone').value='';
        document.getElementById('add-sp-panel').classList.remove('open');
        loadSalespersons();
    } catch(e){showToast('❌ '+(JSON.parse(e.message)?.detail||'Failed'),'error');}
}
async function toggleSP(id,active) {
    try { await api('PUT',`/admin/salespersons/${id}`,{active}); showToast(active?'✅ Activated':'Deactivated','success'); loadSalespersons(); }
    catch(e){showToast('Update failed','error');}
}
// ── Customers ─────────────────────────────────────────────────────────────────
async function loadCustomers() {
    document.getElementById('customer-tbody').innerHTML='<tr><td colspan="7" style="text-align:center;color:#aaa;padding:24px">Loading...</td></tr>';
    document.getElementById('customer-cards').innerHTML='<div class="empty">Loading...</div>';
    try { const data=await api('GET','/admin/customers'); renderCustomers(data.customers||[]); }
    catch(e){
        document.getElementById('customer-tbody').innerHTML='<tr><td colspan="7" style="text-align:center;color:#e67e22;padding:24px">Failed</td></tr>';
        document.getElementById('customer-cards').innerHTML='<div class="empty" style="color:#e67e22">Failed to load</div>';
    }
}
function renderCustomers(customers) {
    document.getElementById('stat-total').textContent=customers.length;
    document.getElementById('stat-active').textContent=customers.filter(c=>c.is_active).length;
    document.getElementById('stat-inactive').textContent=customers.filter(c=>!c.is_active).length;
    document.getElementById('stat-ordered').textContent=customers.filter(c=>c.ordered_today).length;
    const tbody=document.getElementById('customer-tbody');
    if(!customers.length){tbody.innerHTML='<tr><td colspan="7" style="text-align:center;color:#aaa;padding:24px">No customers yet</td></tr>';}
    else tbody.innerHTML=customers.map(c=>{
        const sp=c.salesperson_name?`<span style="font-size:13px">${esc(c.salesperson_name)}</span>`:'<span class="badge unassigned">Unassigned</span>';
        const today=c.ordered_today?'<span class="badge ordered-badge">✅</span>':'<span class="badge pending-badge">⏳</span>';
        const toggle=c.is_active?`<button class="btn btn-deactivate" onclick="setStatus(${c.id},false)">Deactivate</button>`:`<button class="btn btn-activate" onclick="setStatus(${c.id},true)">Activate</button>`;
        return `<tr>
            <td><strong>${esc(c.restaurant_name||'—')}</strong></td>
            <td style="font-size:12px;color:#888">${esc(c.phone_number)}</td>
            <td>${esc(c.area||'')}</td>
            <td>${sp}</td><td>${today}</td>
            <td>${c.is_active?'<span class="badge active">Active</span>':'<span class="badge inactive">Inactive</span>'}</td>
            <td style="display:flex;gap:5px;flex-wrap:wrap">
                <button class="btn btn-assign" onclick="openAssignModal(${c.id},'${(c.restaurant_name||'').replace(/'/g,"\\'")}',${c.salesperson_id||'null'},'${(c.area||'').replace(/'/g,"\\'")}')">Assign</button>
                ${toggle}
                <button class="btn" style="background:#f3e5f5;color:#6a1b9a" onclick="openHistory(${c.id},'${(c.restaurant_name||'').replace(/'/g,"\\'")}')">History</button>
                <button class="btn" style="background:#e8f5e9;color:#2e7d32" onclick="openPostOrderModal(${c.id},'${(c.restaurant_name||'').replace(/'/g,"\\'")}')">📝 Post Order</button>
            </td>
        </tr>`;
    }).join('');
    const cards=document.getElementById('customer-cards');
    if(!customers.length){cards.innerHTML='<div class="empty">No customers yet</div>';return;}
    cards.innerHTML=customers.map(c=>{
        const todayBadge=c.ordered_today?'<span class="badge ordered-badge">✅ Ordered</span>':'<span class="badge pending-badge">⏳ Pending</span>';
        const spText=c.salesperson_name?`👤 ${esc(c.salesperson_name)}`:'Unassigned';
        const toggle=c.is_active?`<button class="btn btn-deactivate" onclick="setStatus(${c.id},false)">Deactivate</button>`:`<button class="btn btn-activate" onclick="setStatus(${c.id},true)">Activate</button>`;
        return `<div class="mobile-card ${!c.is_active?'inactive':''}">
            <div class="mobile-card-row">
                <div>
                    <div class="mobile-card-name">${esc(c.restaurant_name||'—')}</div>
                    <div class="mobile-card-sub">${esc(c.phone_number)}${c.area?' · '+esc(c.area):''} · ${spText}</div>
                </div>
                ${todayBadge}
            </div>
            <div class="mobile-card-actions">
                <button class="btn btn-assign" onclick="openAssignModal(${c.id},'${(c.restaurant_name||'').replace(/'/g,"\\'")}',${c.salesperson_id||'null'},'${(c.area||'').replace(/'/g,"\\'")}')">Assign</button>
                ${toggle}
                <button class="btn" style="background:#f3e5f5;color:#6a1b9a" onclick="openHistory(${c.id},'${(c.restaurant_name||'').replace(/'/g,"\\'")}')">History</button>
                <button class="btn" style="background:#e8f5e9;color:#2e7d32" onclick="openPostOrderModal(${c.id},'${(c.restaurant_name||'').replace(/'/g,"\\'")}')">📝 Post Order</button>
            </div>
        </div>`;
    }).join('');
}
function openAssignModal(cid,rname,spId,area) {
    currentAssignId=cid;
    document.getElementById('modal-customer-name').textContent=rname;
    document.getElementById('modal-area').value=area||'';
    document.getElementById('modal-sp').value=spId||'';
    document.getElementById('assign-modal').classList.add('open');
}
async function saveAssignment() {
    const area=document.getElementById('modal-area').value.trim(), spId=document.getElementById('modal-sp').value, body={};
    if(area) body.area=area; if(spId) body.salesperson_id=parseInt(spId);
    if(!area&&!spId){showToast('Enter area or select salesperson','error');return;}
    try { const data=await api('POST',`/admin/customers/${currentAssignId}/assign`,body); showToast(`✅ ${data.customer.restaurant_name} assigned`,'success'); closeModal('assign-modal'); loadCustomers(); }
    catch(e){showToast('Assignment failed','error');}
}
async function setStatus(cid,isActive) {
    try { const data=await api('PUT',`/admin/customers/${cid}/status`,{is_active:isActive}); showToast(`✅ ${data.customer.restaurant_name} → ${isActive?'Active':'Inactive'}`,'success'); loadCustomers(); }
    catch(e){showToast('Update failed','error');}
}
async function openHistory(cid,rname) {
    document.getElementById('history-customer-name').textContent=rname;
    document.getElementById('history-body').innerHTML='<div class="empty">Loading...</div>';
    document.getElementById('history-modal').classList.add('open');
    try {
        const data=await api('GET',`/admin/customers/${cid}/orders`);
        const orders=data.orders||[];
        if(!orders.length){document.getElementById('history-body').innerHTML='<div class="empty">No orders found</div>';return;}
        document.getElementById('history-body').innerHTML=orders.map(o=>{
            const items=(o.items||[]).map(i=>`${esc(i.product)} — ${i.quantity} ${esc(i.unit)}`).join('<br>');
            const dl=o.delivery_date||(o.created_at?o.created_at.substring(0,10):'—');
            const unclearItems=o.unclear_items||[];
            const tag=o.is_cancelled?'<span class="badge inactive" style="font-size:10px">Cancelled</span>':o.is_unclear?'<span class="badge unclear" style="font-size:10px">Unclear</span>':unclearItems.length?'<span class="badge unclear" style="font-size:10px">Partial</span>':'<span class="badge active" style="font-size:10px">OK</span>';
            return `<div class="history-item ${o.is_cancelled?'history-cancelled':''}">
                <div class="history-date">${dl} ${tag}</div>
                <div class="history-items">${items||'<em style="color:#aaa">No parsed items</em>'}</div>
                ${unclearItems.length?`<div style="font-size:11px;color:#e53e3e;margin-top:4px;">❓ ${unclearItems.map(r=>`<span style="font-family:monospace">${esc(r)}</span>`).join(', ')}</div>`:''}
                ${o.is_unclear?`<div style="font-size:11px;color:#e67e22;margin-top:4px">${esc(o.unclear_reason||'')}</div>`:''}
            </div>`;
        }).join('');
    } catch(e){document.getElementById('history-body').innerHTML='<div class="empty" style="color:#e67e22">Failed to load</div>';}
}
// ── Add Customer Modal ─────────────────────────────────────────────────────────
function openAddCustomerModal() {
    const sel = document.getElementById('ac-sp');
    sel.innerHTML = '<option value="">— Assign later —</option>';
    allSalespersons.filter(s => s.active).forEach(s => {
        sel.innerHTML += `<option value="${s.id}">${esc(s.name)}</option>`;
    });
    ['ac-phone','ac-name','ac-area'].forEach(id => document.getElementById(id).value = '');
    sel.value = '';
    document.getElementById('add-customer-modal').classList.add('open');
}
async function submitAddCustomer() {
    const phone = document.getElementById('ac-phone').value.trim();
    const name  = document.getElementById('ac-name').value.trim();
    const area  = document.getElementById('ac-area').value.trim();
    const spId  = document.getElementById('ac-sp').value;
    if (!phone || !name) { showToast('⚠️ Phone and restaurant name are required', 'error'); return; }
    const body = { phone, restaurant_name: name };
    if (area)  body.area = area;
    if (spId)  body.salesperson_id = parseInt(spId);
    try {
        const data = await api('POST', '/admin/customers', body);
        showToast(`✅ ${data.customer.restaurant_name} added!`, 'success');
        closeModal('add-customer-modal');
        loadCustomers();
    } catch(e) {
        const msg = (() => { try { return JSON.parse(e.message)?.detail; } catch { return null; } })();
        showToast('❌ ' + (msg || 'Failed to add customer'), 'error');
    }
}
// ── Post Order on Behalf ──────────────────────────────────────────────────────
let _postOrderCustomerId = null;
function openPostOrderModal(cid, rname) {
    _postOrderCustomerId = cid;
    document.getElementById('po-customer-name').textContent = rname || ('Customer #' + cid);
    document.getElementById('po-message').value = '';
    const btn = document.getElementById('po-submit-btn');
    btn.disabled = false;
    btn.textContent = 'Post Order';
    document.getElementById('post-order-modal').classList.add('open');
    // Auto-focus the textarea after the modal transition
    setTimeout(() => document.getElementById('po-message').focus(), 150);
}
async function submitPostOrder() {
    const message = document.getElementById('po-message').value.trim();
    if (!message) {
        showToast('⚠️ Please enter an order message', 'error');
        return;
    }
    const btn = document.getElementById('po-submit-btn');
    btn.disabled = true;
    btn.textContent = 'Posting…';
    try {
        const data = await api(
            'POST',
            `/admin/customers/${_postOrderCustomerId}/post-order`,
            { message }
        );
        const isUnclear = data.status === 'unclear';
        const label = isUnclear
            ? `⚠️ Posted — some items unclear (Order #${data.order_id || '?'})`
            : `✅ Order #${data.order_id || '?'} posted for ${data.customer}`;
        showToast(label, 'success');
        closeModal('post-order-modal');
        // Reload so the new order appears immediately
        setTimeout(() => location.reload(), 800);
    } catch(e) {
        let msg = 'Failed to post order';
        try { msg = JSON.parse(e.message)?.detail || msg; } catch(_) {}
        showToast('❌ ' + msg, 'error');
        btn.disabled = false;
        btn.textContent = 'Post Order';
    }
}
// ─────────────────────────────────────────────────────────────────────────────
// ── Pending ───────────────────────────────────────────────────────────────────
async function loadPending() {
    document.getElementById('pending-content').innerHTML='<div class="empty">Loading...</div>';
    try {
        const data=await api('GET','/admin/pending');
        const groups=data.groups||[];
        document.getElementById('pending-total').textContent=data.total_pending;
        document.getElementById('pending-groups').textContent=groups.filter(g=>g.salesperson_id!==null).length;
        document.getElementById('pending-unassigned').textContent=groups.find(g=>g.salesperson_id===null)?.pending_count||0;
        if(!data.total_pending){document.getElementById('pending-content').innerHTML='<div class="empty">✅ All customers have ordered today!</div>';return;}
        document.getElementById('pending-content').innerHTML=groups.map(g=>`
            <div class="pending-group">
                <h3><span>${g.salesperson_id?'👤 '+esc(g.salesperson_name):'⚠️ Unassigned'}</span><span class="badge pending-badge">${g.pending_count} pending</span></h3>
                <ul class="pending-list">${g.customers.map(c=>`<li><span>🏪 ${esc(c.restaurant_name)}</span><span style="font-size:12px;color:#aaa">${esc(c.area||'')}</span></li>`).join('')}</ul>
            </div>`).join('');
    } catch(e){document.getElementById('pending-content').innerHTML='<div class="empty" style="color:#e67e22">Failed to load</div>';}
}
// ── Window Status ─────────────────────────────────────────────────────────────
async function loadWindowStatus() {
    document.getElementById('window-list').innerHTML='<div class="empty">Loading...</div>';
    try {
        const data = await api('GET', '/admin/window-status');
        windowData = data.stakeholders || [];
        const open=windowData.filter(s=>s.status==='OPEN').length;
        const atRisk=windowData.filter(s=>s.status==='AT_RISK').length;
        const closed=windowData.filter(s=>s.status==='CLOSED').length;
        document.getElementById('win-open').textContent=open;
        document.getElementById('win-atrisk').textContent=atRisk;
        document.getElementById('win-closed').textContent=closed;
        document.getElementById('win-total').textContent=data.total;
        document.getElementById('window-checked').textContent='Last checked: '+data.checked_at;
        const tabBtn=document.getElementById('window-tab-btn');
        const existingDot=tabBtn.querySelector('.tab-dot');
        if(closed>0||atRisk>0){
            if(!existingDot){const d=document.createElement('span');d.className='tab-dot';d.style.background=closed>0?'#c62828':'#e67e22';tabBtn.appendChild(d);}
        } else existingDot?.remove();
        renderWindowCards(windowData);
    } catch(e){document.getElementById('window-list').innerHTML='<div class="empty" style="color:#e67e22">Failed to load</div>';}
}
function renderWindowCards(rows) {
    const list=document.getElementById('window-list');
    if(!rows.length){list.innerHTML='<div class="empty">No stakeholders found</div>';return;}
    list.innerHTML=rows.map(s=>{
        const dotClass=s.status==='OPEN'?'dot-open':s.status==='AT_RISK'?'dot-atrisk':'dot-closed';
        const statClass=s.status==='OPEN'?'ws-open':s.status==='AT_RISK'?'ws-atrisk':'ws-closed';
        const label=s.status==='OPEN'?s.status_label:s.status==='AT_RISK'?'⚠️ '+s.status_label:'🔴 Closed';
        const roleLabel=s.role==='manager'?'👔 Manager':s.role==='salesperson'?'🧑 Salesperson':'🏪 Customer';
        const action=(s.status==='CLOSED'||s.status==='AT_RISK')?`<div style="font-size:11px;color:#c62828;font-weight:600;margin-top:3px">📞 Ask to send Hi</div>`:'';
        return `<div class="window-mobile-card">
            <span class="window-dot ${dotClass}"></span>
            <div class="window-info">
                <div class="window-info-name">${esc(s.name)}</div>
                <div class="window-info-sub">${roleLabel} · ${esc(s.phone)} · Last: ${esc(s.last_seen_display)}</div>
                ${action}
            </div>
            <div class="window-status-text ${statClass}">${label}</div>
        </div>`;
    }).join('');
}
function filterWindow(filter, btn) {
    document.querySelectorAll('.filter-btn').forEach(b=>b.classList.remove('active'));
    btn.classList.add('active');
    let filtered=windowData;
    if(filter==='CLOSED') filtered=windowData.filter(s=>s.status==='CLOSED');
    else if(filter==='AT_RISK') filtered=windowData.filter(s=>s.status==='AT_RISK');
    else if(filter!=='all') filtered=windowData.filter(s=>s.role===filter);
    renderWindowCards(filtered);
}
// ── Unclear Items ─────────────────────────────────────────────────────────────
async function fetchProductNames() {
    if (productNames.length > 0) return productNames;
    try {
        const names = await api('GET', '/admin/product-names');
        productNames = names;
    } catch(e) { console.error('Failed to load product names', e); }
    return productNames;
}
async function loadUnclearOrders() {
    const container = document.getElementById('unclear-orders-container');
    container.innerHTML = '<div class="empty">Loading...</div>';
    try {
        const [orders, products] = await Promise.all([
            api('GET', '/admin/unclear-items'),
            fetchProductNames(),
        ]);
        const totalItems = orders.reduce((s, o) => s + o.unclear_items.length, 0);
        document.getElementById('unclear-count').textContent = orders.length;
        document.getElementById('unclear-items-count').textContent = totalItems;
        const tabBtn = document.getElementById('unclear-tab-btn');
        const existingDot = tabBtn.querySelector('.tab-dot');
        if (orders.length > 0) {
            if (!existingDot) {
                const d = document.createElement('span');
                d.className = 'tab-dot';
                tabBtn.appendChild(d);
            }
        } else {
            existingDot?.remove();
        }
        if (orders.length === 0) {
            container.innerHTML = `<div class="empty" style="color:#38a169;">✅ All orders fully parsed — no unclear items!</div>`;
            // ② Also load noise phrases when unclear orders finish loading
            loadNoisePhrases();
            return;
        }
        const productOptions = products.map(p => `<option value="${esc(p)}">${esc(p)}</option>`).join('');
        container.innerHTML = orders.map(order => {
            const parsedSection = order.parsed_items.length ? `
                <div style="margin-bottom:12px;">
                    <div class="unclear-section-label unclear-parsed-label">✅ Parsed items (included in product summary):</div>
                    ${order.parsed_items.map(i => `
                        <div style="font-size:13px;color:#2d3748;padding:2px 0;">
                            &nbsp;&nbsp;• ${esc(i.product)} — ${Number.isInteger(i.quantity) || i.quantity%1===0 ? parseInt(i.quantity) : i.quantity} ${esc(i.unit)}
                        </div>`).join('')}
                </div>` : '';
            // ③ Updated unclear item rows — now include the 🚫 Noise button
            const unclearSection = `
                <div>
                    <div class="unclear-section-label unclear-raw-label">❓ Unresolved items — assign correct product:</div>
                    ${order.unclear_items.map((rawLine, idx) => `
                        <div class="unclear-item-row">
                            <div class="unclear-raw-pill">${esc(rawLine)}</div>
                            <select class="unclear-select" id="sel-${order.order_id}-${idx}">
                                <option value="">— select product —</option>
                                ${productOptions}
                            </select>
                            <button class="unclear-save-btn"
                                onclick="resolveItem('${esc(rawLine).replace(/'/g,"\\'")}', 'sel-${order.order_id}-${idx}', this)">
                                Save &amp; Apply
                            </button>
                            <button class="unclear-save-btn" style="background:#718096;"
                                onclick="markAsNoise('${esc(rawLine).replace(/'/g,"\\'")}', this)">
                                🚫 Noise
                            </button>
                        </div>`).join('')}
                </div>`;
            return `
                <div class="unclear-order-card">
                    <div class="unclear-order-header">
                        <div>
                            <div class="unclear-order-name">🏪 ${esc(order.customer_name)}</div>
                            <div class="unclear-order-meta">📱 ${esc(order.customer_phone)} &nbsp;·&nbsp; ${esc(order.delivery_date)}</div>
                        </div>
                        <span class="badge unclear">${order.unclear_items.length} unclear</span>
                    </div>
                    ${parsedSection}
                    ${unclearSection}
                    <details style="margin-top:10px;">
                        <summary style="font-size:12px;color:#aaa;cursor:pointer;">📄 Full raw message</summary>
                        <pre style="font-size:12px;color:#4a5568;background:#f7fafc;border-radius:6px;padding:8px;margin-top:6px;white-space:pre-wrap;word-break:break-word;">${esc(order.raw_message)}</pre>
                    </details>
                </div>`;
        }).join('');
        // ② Also refresh noise phrases count after loading unclear orders
        loadNoisePhrases();
    } catch(e) {
        container.innerHTML = `<div class="empty" style="color:#e53e3e;">Failed to load: ${esc(e.message)}</div>`;
    }
}
function _extractProductName(rawLine) {
    const clean = rawLine.replace(/__+/g, '').trim();
    const m = clean.match(/^(.+?)\s*[-:]?\s*([\d\.]+)\s*(kg|kgs|nos|pcs|psc|pc|pieces?)?\s*$/i);
    if (m) return m[1].trim().toLowerCase();
    return clean.toLowerCase();
}
async function resolveItem(rawText, selectId, btn) {
    const select = document.getElementById(selectId);
    const canonical = select ? select.value : '';
    if (!canonical) { showToast('Please select a product first', 'error'); return; }
    const productName = _extractProductName(rawText);
    btn.disabled = true;
    btn.textContent = 'Saving…';
    try {
        const data = await api('POST', '/admin/unclear-items/resolve', {
            raw_text: productName,
            canonical_product_name: canonical,
        });
        btn.textContent = `✅ ${data.orders_patched} order${data.orders_patched !== 1 ? 's' : ''} updated`;
        btn.classList.add('done');
        showToast(`✅ "${productName}" → ${canonical} (${data.orders_patched} orders updated)`, 'success');
        setTimeout(() => { loadUnclearOrders(); loadAliases(); }, 1500);
    } catch(e) {
        btn.disabled = false;
        btn.textContent = 'Save & Apply';
        let msg = e.message;
        try { msg = JSON.parse(e.message)?.detail || msg; } catch(_){}
        showToast('❌ ' + msg, 'error');
    }
}
async function loadAliases() {
    const container = document.getElementById('aliases-container');
    try {
        const aliases = await api('GET', '/admin/unclear-items/aliases');
        document.getElementById('unclear-aliases-count').textContent = aliases.length;
        if (!aliases.length) {
            container.innerHTML = '<div class="empty" style="padding:16px">No aliases saved yet.</div>';
            return;
        }
        container.innerHTML = `
            <div class="summary-table">
                <table class="aliases-table">
                    <thead>
                        <tr>
                            <th>Customer typed</th>
                            <th>Maps to</th>
                            <th>Saved on</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        ${aliases.map(a => `
                            <tr id="alias-row-${a.id}">
                                <td class="alias-raw">${esc(a.raw_text)}</td>
                                <td style="color:#2d3748;font-weight:600;">${esc(a.canonical_product_name)}</td>
                                <td style="color:#aaa;font-size:12px;">${a.created_at ? a.created_at.substring(0,10) : '—'}</td>
                                <td>
                                    <button onclick="deleteAlias(${a.id})"
                                        style="font-size:11px;color:#e53e3e;background:none;border:1px solid #e53e3e;border-radius:4px;padding:2px 8px;cursor:pointer;">
                                        Delete
                                    </button>
                                </td>
                            </tr>`).join('')}
                    </tbody>
                </table>
            </div>`;
    } catch(e) {
        container.innerHTML = '<div class="empty" style="color:#e53e3e;">Failed to load aliases.</div>';
    }
}
async function deleteAlias(id) {
    if (!confirm('Delete this alias? Future orders with this text will be flagged unclear again.')) return;
    try {
        await api('DELETE', `/admin/unclear-items/aliases/${id}`);
        showToast('Alias deleted', '');
        document.getElementById(`alias-row-${id}`)?.remove();
        const count = document.querySelectorAll('[id^="alias-row-"]').length;
        document.getElementById('unclear-aliases-count').textContent = count;
        if (count === 0) loadAliases();
    } catch(e) { showToast('Delete failed', 'error'); }
}
// ── Noise Phrases ─────────────────────────────────────────────────────────────
async function markAsNoise(rawText, btn) {
    const productName = _extractProductName(rawText);
    if (!confirm(`Mark "${productName}" as noise/irrelevant?\n\nThe parser will silently skip this text in all future orders.`)) return;
    btn.disabled = true;
    btn.textContent = 'Saving…';
    try {
        const data = await api('POST', '/admin/noise-phrases', { raw_text: productName });
        btn.textContent = '🚫 Ignored';
        btn.style.background = '#c53030';
        showToast(
            data.already_existed
                ? `"${productName}" was already marked as noise`
                : `✅ "${productName}" added to noise list`,
            'success'
        );
        setTimeout(() => { loadUnclearOrders(); loadNoisePhrases(); }, 1200);
    } catch(e) {
        btn.disabled = false;
        btn.textContent = '🚫 Noise';
        showToast('❌ Failed to save noise phrase', 'error');
    }
}
async function loadNoisePhrases() {
    const container = document.getElementById('noise-container');
    if (!container) return;
    try {
        const phrases = await api('GET', '/admin/noise-phrases');
        document.getElementById('unclear-noise-count').textContent = phrases.length;
        if (!phrases.length) {
            container.innerHTML = '<div class="empty" style="padding:16px">No noise phrases saved yet.</div>';
            return;
        }
        container.innerHTML = `
            <div class="summary-table">
                <table class="aliases-table">
                    <thead>
                        <tr>
                            <th>Ignored text</th>
                            <th>Saved on</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        ${phrases.map(p => `
                            <tr id="noise-row-${p.id}">
                                <td class="alias-raw">${esc(p.raw_text)}</td>
                                <td style="color:#aaa;font-size:12px;">${p.created_at ? p.created_at.substring(0,10) : '—'}</td>
                                <td>
                                    <button onclick="deleteNoisePhrase(${p.id})"
                                        style="font-size:11px;color:#e53e3e;background:none;border:1px solid #e53e3e;border-radius:4px;padding:2px 8px;cursor:pointer;">
                                        Delete
                                    </button>
                                </td>
                            </tr>`).join('')}
                    </tbody>
                </table>
            </div>`;
    } catch(e) {
        if (container) container.innerHTML = '<div class="empty" style="color:#e53e3e;">Failed to load.</div>';
    }
}
async function deleteNoisePhrase(id) {
    if (!confirm('Delete this noise phrase? The parser will flag it as unclear again if seen.')) return;
    try {
        await api('DELETE', `/admin/noise-phrases/${id}`);
        showToast('Noise phrase deleted', '');
        document.getElementById(`noise-row-${id}`)?.remove();
        const count = document.querySelectorAll('[id^="noise-row-"]').length;
        document.getElementById('unclear-noise-count').textContent = count;
        if (count === 0) loadNoisePhrases();
    } catch(e) { showToast('Delete failed', 'error'); }
}
// ── Failed Messages ────────────────────────────────────────────────────────────
async function loadFailedMessages() {
    const list=document.getElementById('failed-list');
    list.innerHTML='<div class="empty">Loading...</div>';
    try {
        const data=await api('GET','/webhook/reliability/manual-review');
        const tabBtn=document.getElementById('failed-tab-btn');
        if(!data.messages?.length){
            list.innerHTML='<div class="empty" style="padding:60px">✅ No failed messages.</div>';
            tabBtn.classList.add('hidden');
            switchTab('orders', document.querySelector('.tab-btn'));
            return;
        }
        tabBtn.classList.remove('hidden');
        list.innerHTML=data.messages.map(m=>`
            <div class="failed-card ${m.processing_status==='MANUAL_REVIEW'?'manual':''}" id="fc-${m.id}">
                <div class="failed-card-header">
                    <span class="failed-card-phone">📱 ${esc(m.customer_phone)}</span>
                    <span class="failed-card-time">${m.received_at?new Date(m.received_at).toLocaleString('en-IN',{timeZone:'Asia/Kolkata'}):''}</span>
                </div>
                <div class="failed-card-message">${m.raw_message?`"${esc(m.raw_message.substring(0,300))}${m.raw_message.length>300?'…':''}"` :'<em style="color:#aaa">No text</em>'}</div>
                <div class="failed-card-reason ${m.processing_status==='MANUAL_REVIEW'?'orange':''}">❗ ${esc(m.failure_reason||'Unknown')}</div>
                <div class="failed-card-meta">
                    <span class="badge ${m.processing_status==='MANUAL_REVIEW'?'manual-badge':'failed-badge'}">${m.processing_status}</span>
                    <span class="badge attempts-badge">${m.attempts} attempt${m.attempts!==1?'s':''}</span>
                    ${m.ack_failed?'<span class="badge ack-badge">Ack failed</span>':''}
                    ${m.linked_order_id?`<span class="badge active">Order #${m.linked_order_id}</span>`:''}
                </div>
                <div class="failed-card-actions">
                    <button class="btn btn-retry" onclick="retryMessage(${m.id})">↻ Retry</button>
                    <button class="btn btn-resolve" onclick="resolveMessage(${m.id})">✓ Resolve</button>
                </div>
            </div>`).join('');
    } catch(e){list.innerHTML='<div class="empty" style="color:#e67e22">Failed to load.</div>';}
}
async function retryMessage(id) {
    if(!confirm('Retry this message now?')) return;
    try { const data=await api('POST',`/webhook/reliability/manual-review/${id}/retry`); showToast(`✅ Retried — Order #${data.order_id||'?'} created`,'success'); document.getElementById(`fc-${id}`)?.remove(); checkEmptyFailed(); }
    catch(e){let msg='Retry failed'; try{msg=JSON.parse(e.message)?.detail||msg;}catch(_){} showToast('❌ '+msg,'error');}
}
async function resolveMessage(id) {
    if(!confirm('Mark as resolved?')) return;
    try { await api('POST',`/webhook/reliability/manual-review/${id}/resolve`); showToast('✓ Resolved','success'); document.getElementById(`fc-${id}`)?.remove(); checkEmptyFailed(); }
    catch(e){showToast('❌ Failed','error');}
}
function checkEmptyFailed() {
    const list=document.getElementById('failed-list');
    if(!list.querySelector('.failed-card')){
        list.innerHTML='<div class="empty" style="padding:60px">✅ No failed messages.</div>';
        const tabBtn=document.getElementById('failed-tab-btn');
        tabBtn.classList.add('hidden');
        switchTab('orders', document.querySelector('.tab-btn'));
    }
}
// ── Init ──────────────────────────────────────────────────────────────────────
(async function initUnclearBadge() {
    try {
        const orders = await api('GET', '/admin/unclear-items');
        if (orders && orders.length > 0) {
            const tabBtn = document.getElementById('unclear-tab-btn');
            if (!tabBtn.querySelector('.tab-dot')) {
                const d = document.createElement('span');
                d.className = 'tab-dot';
                tabBtn.appendChild(d);
            }
        }
    } catch(e) {}
})();
async function moveToNextDay(orderId) {
    try {
        await api('PUT', `/admin/orders/${orderId}/next-day`, { is_next_day: true });
        showToast('✅ Moved to next day', 'success');
        location.reload();
    } catch(e) {
        showToast('❌ ' + (JSON.parse(e.message)?.detail || 'Failed'), 'error');
    }
}
async function revertToToday(orderId) {
    try {
        await api('PUT', `/admin/orders/${orderId}/next-day`, { is_next_day: false });
        showToast('✅ Reverted to today', 'success');
        location.reload();
    } catch(e) {
        showToast('❌ ' + (JSON.parse(e.message)?.detail || 'Failed'), 'error');
    }
}
async function cancelOrder(orderId, customerName) {
    const reason = prompt(
        `Cancel order for ${customerName}?\n\nEnter reason to send to customer (or leave blank for default):`,
        ""
    );
    if (reason === null) return; // user hit Cancel on the prompt
    try {
        await api('POST', `/admin/orders/${orderId}/cancel`, { reason: reason.trim() || null });
        showToast(`✅ Order #${orderId} cancelled — customer notified`, 'success');
        setTimeout(() => location.reload(), 800);
    } catch(e) {
        let msg = 'Cancel failed';
        try { msg = JSON.parse(e.message)?.detail || msg; } catch(_) {}
        showToast('❌ ' + msg, 'error');
    }
}
setInterval(() => {
    if (document.getElementById('tab-orders').classList.contains('active')) location.reload();
}, 60000);
